#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <math_constants.h>

// ================= RNG (Philox 4x32-10) =================
static __device__ __forceinline__ uint4 philox4x32_10(uint2 key, uint4 ctr) {
  constexpr uint32_t M0 = 0xD2511F53;
  constexpr uint32_t M1 = 0xCD9E8D57;
  constexpr uint32_t W0 = 0x9E3779B9;
  constexpr uint32_t W1 = 0xBB67AE85;

  uint32_t c0 = ctr.x, c1 = ctr.y, c2 = ctr.z, c3 = ctr.w;
  uint32_t k0 = key.x, k1 = key.y;

#pragma unroll
  for (int round = 0; round < 10; ++round) {
    uint32_t hi0 = __umulhi(M0, c0);
    uint32_t lo0 = M0 * c0;
    uint32_t hi1 = __umulhi(M1, c2);
    uint32_t lo1 = M1 * c2;

    uint32_t n0 = hi1 ^ c1 ^ k0;
    uint32_t n1 = lo1;
    uint32_t n2 = hi0 ^ c3 ^ k1;
    uint32_t n3 = lo0;

    c0 = n0; c1 = n1; c2 = n2; c3 = n3;
    k0 += W0; k1 += W1;
  }
  return make_uint4(c0, c1, c2, c3);
}

// (0,1) open interval using 24 MSBs
static __device__ __forceinline__ float u01_from_uint(uint32_t x) {
  return (float)((x >> 8) + 1u) * (1.0f / 16777217.0f);
}

template <int BLOCK>
static __device__ __forceinline__ float block_reduce_sum(float v) {
  static_assert((BLOCK & (BLOCK - 1)) == 0, "BLOCK must be power of two");
  __shared__ float smem[BLOCK / 32];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

#pragma unroll
  for (int off = 16; off > 0; off >>= 1) v += __shfl_down_sync(0xffffffff, v, off);
  if (lane == 0) smem[warp] = v;
  __syncthreads();

  float out = 0.0f;
  if (warp == 0) {
    out = (lane < (BLOCK / 32)) ? smem[lane] : 0.0f;
#pragma unroll
    for (int off = 16; off > 0; off >>= 1) out += __shfl_down_sync(0xffffffff, out, off);
  }
  out = __shfl_sync(0xffffffff, out, 0);
  __syncthreads();
  return out;
}

// One block per row. Exact for:
// - invalid k path (no filtering): samples from given probs (assumes probs are weights; normalization not required)
// - filtering path for k<=32: exact top-k + renorm + multinomial on that support
template <int BLOCK>
__global__ void topk32_sampling_kernel(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    int64_t* __restrict__ out_samples,
    int batch_size,
    uint64_t seed,
    uint64_t offset) {
  int row = (int)blockIdx.x;
  if (row >= batch_size) return;

  const float* row_probs = probs + (size_t)row * (size_t)kVocabSize129280;
  int k = top_k[row];

  // RNG: one uniform per row
  uint2 key = make_uint2((uint32_t)seed, (uint32_t)(seed >> 32));
  uint64_t ctr64 = offset + (uint64_t)row;
  uint4 ctr = make_uint4((uint32_t)ctr64, (uint32_t)(ctr64 >> 32), 0u, 0u);
  uint4 r = philox4x32_10(key, ctr);
  float u01 = u01_from_uint(r.x);

  // ---------- No filtering (invalid k) ----------
  if (!(k > 0 && k < kVocabSize129280)) {
    float local = 0.0f;
    for (int j = threadIdx.x; j < kVocabSize129280; j += BLOCK) local += row_probs[j];
    float sum_all = block_reduce_sum<BLOCK>(local);

    float thr = 0.0f;
    if (sum_all > 0.0f && isfinite(sum_all)) thr = u01 * sum_all;

    int chosen = 0;

    // 129280 = 4040*32, let one warp do deterministic scan
    if (threadIdx.x < 32) {
      int lane = threadIdx.x;
      float running = 0.0f;

#pragma unroll 1
      for (int base = 0; base < kVocabSize129280; base += 32) {
        float w = row_probs[base + lane];

        float prefix = w;
#pragma unroll
        for (int off = 1; off < 32; off <<= 1) {
          float n = __shfl_up_sync(0xffffffff, prefix, off);
          if (lane >= off) prefix += n;
        }

        float warp_total = __shfl_sync(0xffffffff, prefix, 31);
        float start = running;

        int hit = ((start + prefix) > thr);
        unsigned mask = __ballot_sync(0xffffffff, hit);
        if (mask) {
          int first = __ffs(mask) - 1;
          chosen = base + first;
          break;
        }
        running = start + warp_total;
      }
    }

    if (threadIdx.x == 0) out_samples[row] = (int64_t)chosen;
    return;
  }

  // ---------- Filtering path: supports k <= 32 ----------
  if (k > 32) {
    // Host should have filtered these out; keep deterministic.
    if (threadIdx.x == 0) out_samples[row] = 0;
    return;
  }

  // per-thread top-32 insertion
  float topv[32];
  int topi[32];
#pragma unroll
  for (int t = 0; t < 32; ++t) { topv[t] = -CUDART_INF_F; topi[t] = 0; }

  auto insert = [&](float v, int idx) {
#pragma unroll
    for (int p = 0; p < 32; ++p) {
      bool better = (v > topv[p]) || (v == topv[p] && idx < topi[p]);
      if (better) {
#pragma unroll
        for (int q = 31; q > p; --q) { topv[q] = topv[q - 1]; topi[q] = topi[q - 1]; }
        topv[p] = v; topi[p] = idx;
        break;
      }
    }
  };

  for (int j = threadIdx.x; j < kVocabSize129280; j += BLOCK) insert(row_probs[j], j);

  // Shared candidates
  __shared__ float sh_v[BLOCK * 32];
  __shared__ int   sh_i[BLOCK * 32];

  int sb = threadIdx.x * 32;
#pragma unroll
  for (int t = 0; t < 32; ++t) { sh_v[sb + t] = topv[t]; sh_i[sb + t] = topi[t]; }
  __syncthreads();

  __shared__ int chosen_shared;

  if (threadIdx.x == 0) {
    float g_v[32];
    int g_i[32];
#pragma unroll
    for (int t = 0; t < 32; ++t) { g_v[t] = -CUDART_INF_F; g_i[t] = 0; }

    auto g_insert = [&](float v, int idx) {
#pragma unroll
      for (int p = 0; p < 32; ++p) {
        bool better = (v > g_v[p]) || (v == g_v[p] && idx < g_i[p]);
        if (better) {
#pragma unroll
          for (int q = 31; q > p; --q) { g_v[q] = g_v[q - 1]; g_i[q] = g_i[q - 1]; }
          g_v[p] = v; g_i[p] = idx;
          break;
        }
      }
    };

#pragma unroll 1
    for (int t = 0; t < BLOCK; ++t) {
      int tb = t * 32;
#pragma unroll
      for (int p = 0; p < 32; ++p) {
        if (p >= k) break;
        g_insert(sh_v[tb + p], sh_i[tb + p]);
      }
    }

    float sumk = 0.0f;
#pragma unroll
    for (int p = 0; p < 32; ++p) { if (p >= k) break; sumk += g_v[p]; }

    float thr = 0.0f;
    if (sumk > 0.0f && isfinite(sumk)) thr = u01 * sumk;

    float run = 0.0f;
    int chosen = g_i[0];
#pragma unroll
    for (int p = 0; p < 32; ++p) {
      if (p >= k) break;
      run += g_v[p];
      if (run > thr) { chosen = g_i[p]; break; }
    }
    chosen_shared = chosen;
  }
  __syncthreads();

  if (threadIdx.x == 0) out_samples[row] = (int64_t)chosen_shared;
}

void top_k_sampling_from_probs_v129280_launcher(
    const float* probs,
    const int32_t* top_k,
    int64_t* out_samples,
    int batch_size,
    uint64_t philox_seed,
    uint64_t philox_offset,
    cudaStream_t stream) {
  constexpr int BLOCK = 256;
  dim3 grid(batch_size);
  dim3 block(BLOCK);
  topk32_sampling_kernel<BLOCK><<<grid, block, 0, stream>>>(
      probs, top_k, out_samples, batch_size, philox_seed, philox_offset);
}

#include <torch/extension.h>

#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>
#include <c10/cuda/CUDAException.h>

#include <stdexcept>
#include <tuple>

#include "kernel.h"

static void validate_inputs(const torch::Tensor& probs, const torch::Tensor& top_k) {
  if (!probs.defined() || !top_k.defined()) throw std::invalid_argument("probs and top_k must be defined tensors.");
  if (!probs.device().is_cuda() || !top_k.device().is_cuda()) throw std::invalid_argument("probs and top_k must be CUDA tensors.");
  if (probs.scalar_type() != torch::kFloat32) throw std::invalid_argument("probs must be torch.float32.");
  if (top_k.scalar_type() != torch::kInt32) throw std::invalid_argument("top_k must be torch.int32.");
  if (probs.dim() != 2) throw std::invalid_argument("probs must be 2D [batch_size, vocab_size].");
  if (top_k.dim() != 1) throw std::invalid_argument("top_k must be 1D [batch_size].");
  if (probs.size(1) != kVocabSize129280) throw std::invalid_argument("vocab_size must be exactly 129280.");
  if (top_k.size(0) != probs.size(0)) throw std::invalid_argument("top_k.size(0) must equal probs.size(0).");
  if (!probs.is_contiguous()) throw std::invalid_argument("probs must be contiguous.");
  if (!top_k.is_contiguous()) throw std::invalid_argument("top_k must be contiguous.");
}

// Exact reference behavior using ATen ops (GPU), per-row.
// NOTE: Must avoid assigning a 0-dim tensor into a tensor element directly (can error).
static torch::Tensor exact_fallback(const torch::Tensor& probs, const torch::Tensor& top_k) {
  const int64_t batch = probs.size(0);
  auto samples = torch::empty({batch}, torch::TensorOptions().dtype(torch::kInt64).device(probs.device()));

  for (int64_t i = 0; i < batch; ++i) {
    torch::Tensor row = probs[i];
    int64_t k = (int64_t)top_k[i].item<int32_t>();

    if (k > 0 && k < kVocabSize129280) {
      auto sort_out = row.sort(/*dim=*/0, /*descending=*/true);
      torch::Tensor idx_sorted = std::get<1>(sort_out);
      torch::Tensor keep_idx = idx_sorted.narrow(/*dim=*/0, /*start=*/0, /*length=*/k);

      torch::Tensor filtered = torch::zeros_like(row);
      filtered.index_put_({keep_idx}, row.index({keep_idx}));
      torch::Tensor s = filtered.sum();
      row = filtered / s;
    }

    // multinomial returns [1] int64
    torch::Tensor one = torch::multinomial(row, /*num_samples=*/1, /*replacement=*/true);
    // write as scalar to avoid shape/dtype issues
    samples[i] = one.item<int64_t>();
  }
  return samples;
}

static torch::Tensor run_impl(torch::Tensor probs, torch::Tensor top_k) {
  validate_inputs(probs, top_k);
  c10::cuda::CUDAGuard device_guard(probs.device());

  const int64_t batch64 = probs.size(0);
  if (batch64 > (int64_t)INT32_MAX) throw std::invalid_argument("batch_size too large for int32 indexing.");
  const int batch = (int)batch64;

  // If any row requires k>32 filtering, use exact fallback (matches reference).
  auto mid = (top_k > 0) & (top_k < kVocabSize129280);
  bool any_k_gt32 = (mid & (top_k > 32)).any().item<bool>();
  if (any_k_gt32) return exact_fallback(probs, top_k);

  auto out = torch::empty({batch64}, torch::TensorOptions().dtype(torch::kInt64).device(probs.device()));

  const float* probs_ptr = probs.data_ptr<float>();
  const int32_t* topk_ptr = top_k.data_ptr<int32_t>();
  int64_t* out_ptr = out.data_ptr<int64_t>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  // Philox state: request ceil(batch/4) * 4 32-bit outputs to be safe; we use 1 per row.
  auto gen = at::cuda::getDefaultCUDAGenerator(probs.device().index());
  const uint64_t counter_offset = (uint64_t)batch64; // one counter per row in our kernel
  at::PhiloxCudaState state = gen->philox_cuda_state(counter_offset);

  top_k_sampling_from_probs_v129280_launcher(
      probs_ptr, topk_ptr, out_ptr, batch, state.seed_, state.offset_, stream);

  C10_CUDA_CHECK(cudaGetLastError());
  return out;
}

torch::Tensor run(pybind11::args args, pybind11::kwargs kwargs) {
  torch::Tensor probs;
  torch::Tensor top_k;

  if (kwargs) {
    if (kwargs.contains("probs")) probs = kwargs["probs"].cast<torch::Tensor>();
    if (kwargs.contains("top_k")) top_k = kwargs["top_k"].cast<torch::Tensor>();
  }
  if (!probs.defined() || !top_k.defined()) {
    if (args.size() != 2) throw std::invalid_argument("run expects (probs, top_k) either positionally or as kwargs.");
    probs = args[0].cast<torch::Tensor>();
    top_k = args[1].cast<torch::Tensor>();
  }

  return run_impl(probs, top_k);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
